customCss:
@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@300;400;500;600;700&display=swap');
:root { --font-body: 'JetBrains Mono', monospace; --font-display: 'JetBrains Mono', monospace; --radius: 0px; --ambient-glow-opacity: 0.18; }

/* ── CRT scanlines over everything ── */
body::after { content: ''; position: fixed; inset: 0; background: repeating-linear-gradient(0deg, transparent, transparent 1px, rgba(0,0,0,0.08) 1px, rgba(0,0,0,0.08) 2px); pointer-events: none; z-index: 9999; }

/* ── CRT vignette: darkened edges ── */
body::before { content: ''; position: fixed; inset: 0; background: radial-gradient(ellipse at center, transparent 60%, rgba(0,0,0,0.5) 100%); pointer-events: none; z-index: 9998; }

/* ── Phosphor text glow on everything ── */
body { text-shadow: 0 0 3px rgba(51,255,0,0.35); }
h1, h2, h3, .page-title { text-shadow: 0 0 6px rgba(51,255,0,0.5), 0 0 12px rgba(51,255,0,0.2); }

/* ── Cards: terminal window style ── */
.media-card-image { border: 1px solid rgba(51,255,0,0.2); }
.media-card:hover .media-card-image { border-color: rgba(51,255,0,0.6); box-shadow: 0 0 10px rgba(51,255,0,0.3), 0 0 25px rgba(51,255,0,0.1); }
.media-card:hover { transform: none; filter: brightness(1.2); }

/* ── Sidebar: terminal panel ── */
aside { border-right: 1px solid rgba(51,255,0,0.2) !important; }
.sidebar-logo-icon { border: 1px solid rgba(51,255,0,0.4); }
.sidebar-logo-text { text-transform: uppercase; letter-spacing: 0.2em; font-size: 0.65rem; }

/* ── All section headers: monospaced, prefixed feel ── */
.section-header { text-transform: uppercase; letter-spacing: 0.25em; font-size: 0.65rem; opacity: 0.8; }

/* ── Badges: minimal terminal tags ── */
.metadata-badge { border: 1px solid rgba(51,255,0,0.25); text-transform: uppercase; letter-spacing: 0.15em; font-size: 0.55rem; }

/* ── Input fields: terminal prompt style ── */
input, textarea, select { border: 1px solid rgba(51,255,0,0.2) !important; caret-color: #33ff00; }
input:focus, textarea:focus, select:focus { border-color: rgba(51,255,0,0.5) !important; box-shadow: 0 0 8px rgba(51,255,0,0.2); }

/* ── Buttons: outlined, no fill ── */
.pill-primary { background: transparent !important; border: 1px solid #33ff00; color: #33ff00 !important; box-shadow: 0 0 8px rgba(51,255,0,0.2); }
.pill-primary:hover { background: rgba(51,255,0,0.1) !important; box-shadow: 0 0 16px rgba(51,255,0,0.4); }

/* ── Progress bars: green scanline ── */
.progress-fill { box-shadow: 0 0 6px rgba(51,255,0,0.5); }

/* ── Surface panels: bordered ── */
.surface-panel { border: 1px solid rgba(51,255,0,0.12); }

/* ── Hero: desaturated, green-tinted ── */
.home-hero img { filter: saturate(0) brightness(0.6) sepia(1) hue-rotate(70deg) saturate(2); }

/* ── Glass effects: green tinted ── */
.glass, .glass-subtle, .glass-dark { border: 1px solid rgba(51,255,0,0.1); }
